Iată o implementare minimală:

class EventEmitter:
    def __init__(self):
        self._handlers: dict[str, list] = {}

    def on(self, event: str, handler):
        self._handlers.setdefault(event, []).append(handler)

    def emit(self, event: str, data=None):
        for handler in self._handlers.get(event, []):
            handler(data)


class OrderService(EventEmitter):
    def place_order(self, order: dict):
        print(f"Comanda {order['id']} plasată")
        self.emit('order_placed', order)


def send_confirmation_email(order):
    print(f"Email trimis pentru comanda {order['id']}")

def update_inventory(order):
    print(f"Stoc actualizat pentru comanda {order['id']}")


service = OrderService()
service.on('order_placed', send_confirmation_email)
service.on('order_placed', update_inventory)
service.place_order({'id': 'ORD-001', 'product': 'laptop'})

OrderService nu știe nimic despre email sau inventar — adaugi sau elimini observers fără să modifici clasa.
